setLesson(item) {
      let split = item.time.split("-");
      let week = parseInt(split[0]);
      let lesson = parseInt(split[1]);
      let length = parseInt(split[2]);
      for (let i = 0; i < length; i++) {
        this.tableData[week - 1][lesson - 1 + i] = {
          courseName: item.courseName,
          teacherName: item.teacherName,
          location: item.location
        };
      }啥意思

clearTable() {
      let table = [];
      for (let i = 0; i < 7; i++) {
        let arr = [];
        for (let i2 = 0; i2 < 10; i2++) {
          arr.push({
            courseName: "",
            teacherName: "",
            location: ""
          });
        }
        table.push(arr);
      }
      this.tableData = table;
    },啥意思

digital2Chinese(num, identifier) {
      const character = [
        "零",
        "一",
        "二",
        "三",
        "四",
        "五",
        "六",
        "七",
        "八",
        "九",
        "十"
      ];
      return identifier === "week" && num === 7 ? "日" : character[num];
    }啥意思

create() {
      this.entityForm = {
        id: -1,
        teacherId: null,
        name: "",
        grade: 2019,
        time: "",
        location: "",
        credit: 2,
        maxSize: 50,
        examDate: null,
        examLocation: null,
        courseType:null,
        courseStatus:null
      };
      this.courseDay = 1;
      this.courseTime = 1;
      this.courseLength = 2;
      this.editing = true;
    },啥意思

edit(id) {
      api.get(id).then(res => {
        let split = res.time.split("-");
        this.courseDay = parseInt(split[0]) - 1;
        this.courseTime = parseInt(split[1]) - 1;
        this.courseLength = parseInt(split[2]);
        this.entityForm = res;
        this.editing = true;
      });
    },啥意思

save() {
      let day = this.courseDay + 1;
      let time = this.courseTime + 1;
      this.entityForm.time = day + "-" + time + "-" + this.courseLength;

      if (this.entityForm.id === -1) {
        api.create(this.entityForm).then(() => {
          this.finishSave();
        });
      } else {
        api.update(this.entityForm).then(() => {
          this.finishSave();
        });
      }啥意思

finishSave() {
      this.$message.success("成功");
      this.getPage(this.pageIndex);
      this.editing = false;
    },啥意思

deleteItem(id) {
      api.deleteItem(id).then(() => {
        this.$message.success("删除成功");
        this.getPage(this.pageIndex);
      });
